prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?modelName ?created ?orgId ?originalId ?normalizedId WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId ?originalId .
  FILTER(?originalId = "262d9e9b8c224d918fe800cd2a454ddf" || ?model = <urn:dummy> )
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:modelCreated ?created . }
  OPTIONAL { ?model tai:belongsTo ?org .
             ?org tai:organizationId ?orgId . }
  OPTIONAL { ?model tai:normalizedId ?normalizedId . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?choreoName (COUNT(DISTINCT ?node) AS ?nodeCount) (COUNT(DISTINCT ?seq) AS ?seqFlowCount) (COUNT(DISTINCT ?mflow) AS ?msgFlowCount) WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "262d9e9b8c224d918fe800cd2a454ddf" .
  ?choreo a bboExt:Choreography .
  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .
  OPTIONAL {
    ?node tai:belongsTo ?choreo .
  }
  OPTIONAL {
    ?seq a bbo:SequenceFlow .
    ?seq tai:belongsTo ?choreo .
  }
  OPTIONAL {
    ?mflow a bboExt:MessageFlow .
    ?mflow tai:belongsTo ?choreo .
  }
  OPTIONAL { ?choreo bbo:name ?choreoName . }
}
GROUP BY ?choreo ?choreoName
ORDER BY DESC(?nodeCount)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  (COUNT(DISTINCT ?start) AS ?startEvents)
  (COUNT(DISTINCT ?end) AS ?endEvents)
  (COUNT(DISTINCT ?task) AS ?tasks)
  (COUNT(DISTINCT ?catch) AS ?intermediateCatches)
  (COUNT(DISTINCT ?xor) AS ?exclusiveGateways)
  (COUNT(DISTINCT ?and) AS ?parallelGateways)
  (COUNT(DISTINCT ?eb) AS ?eventBasedGateways)
  (COUNT(DISTINCT ?seq) AS ?seqFlows)
  (COUNT(DISTINCT ?mflow) AS ?messageFlows)
WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "262d9e9b8c224d918fe800cd2a454ddf" .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography .
  ?choreo tai:belongsTo ?defs .

  OPTIONAL { ?start a bboExt:StartEvent ; tai:belongsTo ?choreo . }
  OPTIONAL { ?end a bboExt:EndEvent ; tai:belongsTo ?choreo . }
  OPTIONAL { ?task a bboExt:ChoreographyTask ; tai:belongsTo ?choreo . }
  OPTIONAL { ?catch a bboExt:IntermediateCatchEvent ; tai:belongsTo ?choreo . }
  OPTIONAL { ?xor a bboExt:ExclusiveGateway ; tai:belongsTo ?choreo . }
  OPTIONAL { ?and a bboExt:ParallelGateway ; tai:belongsTo ?choreo . }
  OPTIONAL { ?eb a bboExt:EventBasedGateway ; tai:belongsTo ?choreo . }
  OPTIONAL { ?seq a bbo:SequenceFlow ; tai:belongsTo ?choreo . }
  OPTIONAL { ?mflow a bboExt:MessageFlow ; tai:belongsTo ?choreo . }
}
GROUP BY ?model
